// src/components/common/RoleBasedNav.js
import React from 'react';
import { useAuth } from '../../context/AuthContext';
import './RoleBasedNav.css';

const RoleBasedNav = () => {
    const { user, logout } = useAuth();

    const getRoleIcon = () => {
        switch(user?.role) {
            case 'doctor':
                return '👨‍⚕️';
            case 'admin':
                return '👑';
            default:
                return '👤';
        }
    };

    const getRoleColor = () => {
        switch(user?.role) {
            case 'doctor':
                return '#3498db';
            case 'admin':
                return '#e74c3c';
            default:
                return '#2c3e50';
        }
    };

    return (
        <div className="role-nav">
            <div className="role-badge" style={{ backgroundColor: getRoleColor() }}>
                <span className="role-icon">{getRoleIcon()}</span>
                <span className="role-name">{user?.role || 'patient'}</span>
            </div>
            <div className="nav-links">
                {user?.role === 'doctor' && (
                    <>
                        <a href="/patients" className="nav-link">📋 My Patients</a>
                        <a href="/prescriptions/create" className="nav-link">💊 Write Prescription</a>
                    </>
                )}
                <a href="/dashboard" className="nav-link">📊 Dashboard</a>
                <a href="/profile" className="nav-link">⚙️ Profile</a>
                <button onClick={logout} className="nav-link logout-btn">🚪 Logout</button>
            </div>
        </div>
    );
};

export default RoleBasedNav;
